const topic = $.input.topic || '';
const query = 'trending video content ' + topic + ' script examples';
return { query };

const topic = $.input.topic;
const duration = $.input.targetDuration || '60';
const tone = $.input.tone || 'professional';
const results = $.steps.researchTrending.response.results || [];
let research = '';
results.forEach((r, i) => { research += (i + 1) + '. ' + (r.title || r.url) + ': ' + (r.text || '').slice(0, 200) + '
'; });

const prompt = 'You are an expert video scriptwriter and AI video producer. Create a comprehensive video production plan.

TOPIC: ' + topic + '
DURATION: ' + duration + ' seconds
TONE: ' + tone + '

TRENDING RESEARCH:
' + research + '

Return ONLY valid JSON:
{
  "title": "video title",
  "hook": "attention-grabbing opening line (first 3 seconds)",
  "script": [
    { "timestamp": "0:00-0:05", "narration": "spoken text", "visualDescription": "what appears on screen", "emotion": "tone of delivery" }
  ],
  "totalDuration": "estimated duration",
  "avatarRecommendation": { "type": "professional/casual/animated", "gender": "male/female/neutral", "ageRange": "young/middle/mature" },
  "voiceNotes": { "pace": "slow/medium/fast", "style": "authoritative/friendly/energetic", "emphasis": ["key words to emphasize"] },
  "backgroundMusic": "music style suggestion",
  "callToAction": "end CTA text",
  "tags": ["tag1", "tag2"],
  "thumbnailIdea": "thumbnail description"
}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'Video Script', script: [{ narration: raw }] }; }

const ai = $.steps.parseAI.output;
let doc = 'VIDEO PRODUCTION PLAN
';
doc += '====================

';
doc += 'Title: ' + (ai.title || 'Untitled') + '
';
doc += 'Duration: ' + (ai.totalDuration || $.input.targetDuration + 's') + '
';
doc += 'Tone: ' + $.input.tone + '
';
doc += 'Date: ' + new Date().toISOString().split('T')[0] + '

';
doc += 'HOOK: ' + (ai.hook || '') + '

';
doc += 'SCRIPT
------
';
if (ai.script) { ai.script.forEach(s => { doc += '[' + (s.timestamp || '') + '] ' + (s.narration || '') + '
  Visual: ' + (s.visualDescription || '') + '
  Emotion: ' + (s.emotion || '') + '

'; }); }
doc += 'AVATAR: ' + JSON.stringify(ai.avatarRecommendation || {}) + '
';
doc += 'VOICE: ' + JSON.stringify(ai.voiceNotes || {}) + '
';
doc += 'MUSIC: ' + (ai.backgroundMusic || '') + '
';
doc += 'CTA: ' + (ai.callToAction || '') + '
';
doc += 'THUMBNAIL: ' + (ai.thumbnailIdea || '') + '
';
if (ai.tags) { doc += 'TAGS: ' + ai.tags.join(', ') + '
'; }
const slackText = 'Video script ready: ' + (ai.title || 'Untitled') + ' (' + (ai.totalDuration || '') + ') - ' + (ai.script || []).length + ' scenes';
return { doc, title: (ai.title || 'Video Script') + ' - Production Plan', slackText };
